function hasBuggyHour12Behavior() {
  if (_hasBuggyHour12Behavior == null) {
    _hasBuggyHour12Behavior =
      new Intl.DateTimeFormat('en-US', {
        hour: 'numeric',
        hour12: false
      }).format(new Date(2020, 2, 3, 0)) === '24';
  }

  return _hasBuggyHour12Behavior;
}

const useLocale = <
  K extends PropertyKey = PropertyKey,
  V extends string | ((...params: any[]) => string) = string,
>(
  localeMap?: LocaleMap<K, V>,
): [Record<K, V>, 'cn' | 'en'] => {
  const { id } = useDumiLocale();
  const localeType = id === 'zh-CN' ? 'cn' : 'en';
  return [localeMap?.[localeType] ?? ({} as Record<K, V>), localeType] as const;
};

export function terminalLink(text: string, url: string, options?: { fallback?: (text: string, url: string) => string }): string {
  // Use OSC 8 hyperlink escape sequence
  // See https://gist.github.com/egmontkob/eb114294efbcd5adb1944c9f3cb5feda
  if (
    process.env.FORCE_HYPERLINK
    || (process.stdout.isTTY && !process.env.NO_HYPERLINK)
  ) {
    return `\u001B]8;;${url}\u0007${text}\u001B]8;;\u0007`
  }
  if (options?.fallback)
    return options.fallback(text, url)
  return `${text} (${url})`
}

export function formatTable(lines: string[][], align: string, spaces = '  ') {
  const maxLen: number[] = []
  lines.forEach((line) => {
    line.forEach((char, i) => {
      const len = visualLength(char)
      if (!maxLen[i] || maxLen[i] < len)
        maxLen[i] = len
    })
  })

  return lines.map(line => line.map((chars, i) => {
    const pad = align[i] === 'R' ? visualPadStart : visualPadEnd
    return pad(chars, maxLen[i])
  }).join(spaces))
}

const sortEntries = (props: Record<string, any>): [string, Properties][] => {
  return Object.entries(props).sort(([, a], [, b]) => {
    if (a.isRequired && !b.isRequired) return -1
    if (!a.isRequired && b.isRequired) return 1
    if (a.defaultValue && !b.defaultValue) return -1
    if (!a.defaultValue && b.defaultValue) return 1
    return 0
  })
}

function getUnitTypeFromNumber(number: number): UnitType {
  const abs = Math.abs(number);
  const last = abs % 10;
  const last2 = abs % 100;

  if ((last2 >= 11 && last2 <= 19) || last === 0) return "many";
  if (last === 1) return "one";
  return "few";
}

setName(name: string) {
  const nameNode = this.getNameNode();
  if (this.getName() === name)
    return this;

  if (isValidVariableName(name))
    nameNode.replaceWithText(name);
  else
    nameNode.replaceWithText(`"${name.replaceAll("\"", "\\\"")}"`);
  return this;
}

const prettyBytes = (bytes: number) => {
  if (bytes === 0) return '0 B'
  const unit = ['B', 'KB', 'MB', 'GB', 'TB', 'PB', 'EB', 'ZB', 'YB']
  const exp = Math.floor(Math.log(bytes) / Math.log(1024))
  return `${(bytes / 1024 ** exp).toFixed(2)} ${unit[exp]}`
}

const getTimeBasedFilename = () => {
  const now = new Date(); // 2011-10-05T14:48:00.000Z
  const datetime = now.toISOString().split(".")[0]; // 2011-10-05T14:48:00
  const datetimeNormalized = datetime.replace(/-|:/g, ""); // 20111005T144800
  return `Lerna-Profile-${datetimeNormalized}.json`;
};

export function filterProps<T extends Record<string, any>>(props: T) {
  return Object.keys(props).reduce<FilterPropsRes<T>>((acc, key: keyof T) => {
    if (props[key] !== undefined) {
      acc[key] = props[key];
    }
    return acc;
  }, {} as FilterPropsRes<T>);
}

export function compareDates(date1: Date, date2: Date): boolean {
  if (!date1 && !date2) {
    return true;
  } else if (!date1 || !date2) {
    return false;
  } else {
    return (
      date1.getFullYear() === date2.getFullYear() &&
      date1.getMonth() === date2.getMonth() &&
      date1.getDate() === date2.getDate()
    );
  }
}

