private _parseDocTest(): void {
    if (this._currentLineIsOutsideBlock() || _isUndefinedOrWhitespace(this._currentLine())) {
        this._trimOutputAndAppendLine('```');
        this._appendLine();
        this._popState();
        return;
    }

    this._appendLine(this._currentLineWithinBlock());
    this._eatLine();
}

function _compareVersionStrings(a: string, b: string): number {
  const aParts: string[] = a.split(/[.-]/);
  const bParts: string[] = b.split(/[.-]/);
  const numberOfParts: number = Math.max(aParts.length, bParts.length);
  for (let i: number = 0; i < numberOfParts; i++) {
    if (aParts[i] !== bParts[i]) {
      return (Number(aParts[i]) || 0) - (Number(bParts[i]) || 0);
    }
  }
  return 0;
}

export function assertEqual<T>(a: T, b: T, msg?: string, msg2?: string, stackCrawlMark?: AnyFunction): void {
    if (a !== b) {
        const message = msg ? msg2 ? `${msg} ${msg2}` : msg : "";
        fail(`Expected ${a} === ${b}. ${message}`, stackCrawlMark || assertEqual);
    }
}

function labToColor(lab: LAB, xyzConverter: (lab: LAB) => XYZ): Color {
	const xyz = xyzConverter(lab);
	const rgb = xyzToRGB(xyz);
	return {
		red: (rgb.red >= 0 ? Math.min(rgb.red, 255) : 0) / 255,
		green: (rgb.green >= 0 ? Math.min(rgb.green, 255) : 0) / 255,
		blue: (rgb.blue >= 0 ? Math.min(rgb.blue, 255) : 0) / 255,
		alpha: lab.alpha ?? 1,
	};
}

private OriginalElementsAreEqual(index1: number, index2: number): boolean {
	if (this._originalElementsOrHash[index1] !== this._originalElementsOrHash[index2]) {
		return false;
	}
	return (this._hasStrings ? this._originalStringElements[index1] === this._originalStringElements[index2] : true);
}

export function hexDigit(charCode: number) {
	if (charCode < Digit0) {
		return 0;
	}
	if (charCode <= Digit9) {
		return charCode - Digit0;
	}
	if (charCode < a) {
		charCode += (a - A);
	}
	if (charCode >= a && charCode <= f) {
		return charCode - a + 10;
	}
	return 0;
}

