public decomposeSplit(shouldBeInE1: (repl: T) => boolean): { e1: TEdit; e2: TEdit } {
	const e1: T[] = [];
	const e2: T[] = [];

	let e2delta = 0;
	for (const edit of this.replacements) {
		if (shouldBeInE1(edit)) {
			e1.push(edit);
			e2delta += edit.getNewLength() - edit.replaceRange.length;
		} else {
			e2.push(edit.slice(edit.replaceRange.delta(e2delta), new OffsetRange(0, edit.getNewLength())));
		}
	}
	return { e1: this._createNew(e1), e2: this._createNew(e2) };
}

export function getLocaleOutputPaths(i18n: I18nOptions): Map<string, string> {
  const outputPaths: [string, string][] = i18n.shouldInline
    ? [...i18n.inlineLocales].map((l) => [
        l,
        i18n.flatOutput ? '' : i18n.locales[l].subPath,
      ])
    : [['', '']];

  return new Map(outputPaths);
}

public s3Key(
  type: keyof S3Templates,
  ext?: '.tar.gz' | '.tar.xz' | IConfig.s3Key.Options,
  options: IConfig.s3Key.Options = {},
): string {
  if (typeof ext === 'object') options = ext
  else if (ext) options.ext = ext
  const template = this.updateConfig.s3?.templates?.[options.platform ? 'target' : 'vanilla'][type] ?? ''
  return ejs.render(template, {...(this as any), ...options})
}

export function parentIdsContainSequence (pkgIds: PkgResolutionId[], pkgId1: PkgResolutionId, pkgId2: PkgResolutionId): boolean {
  const pkg1Index = pkgIds.indexOf(pkgId1)
  if (pkg1Index === -1 || pkg1Index === pkgIds.length - 1) {
    return false
  }
  const pkg2Index = pkgIds.lastIndexOf(pkgId2)
  return pkg1Index < pkg2Index && pkg2Index !== pkgIds.length - 1
}

export function mergeBy<T>(arr1: T[], arr2: T[], cb: (element: T) => string): T[] {
  const groupedArr1 = groupBy(arr1, cb)
  const groupedArr2 = groupBy(arr2, cb)
  const result: T[] = Object.values(groupedArr2).map((value) => value[value.length - 1])

  const arr2Keys = Object.keys(groupedArr2)
  Object.entries(groupedArr1).forEach(([key, value]) => {
    if (!arr2Keys.includes(key)) {
      result.push(value[value.length - 1])
    }
  })

  return result
}

const isVersionGreaterOrEqual = (v1: Version, v2: Version): boolean => {
	const majorDiff = v1[0] - v2[0];
	if (majorDiff === 0) {
		const minorDiff = v1[1] - v2[1];
		if (minorDiff === 0) {
			return v1[2] >= v2[2];
		}
		return minorDiff > 0;
	}
	return majorDiff > 0;
};

export function getOperationDefinitions(v3Doc: OpenAPIV3.Document): OperationDefinition[] {
  return Object.entries(v3Doc.paths).flatMap(([path, pathItem]) =>
    !pathItem
      ? []
      : Object.entries(pathItem)
          .filter((arg): arg is [(typeof operationKeys)[number], OpenAPIV3.OperationObject] =>
            operationKeys.includes(arg[0] as any)
          )
          .map(([verb, operation]) => ({
            path,
            verb,
            pathItem,
            operation,
          }))
  );
}

export function removeItems<Item = any>(
  currentItems: Item[],
  removalItems: Item[],
  getItemId: GetItemId<Item>,
): Item[] {
  return currentItems.filter(
    (prevItem) => !removalItems.some((newItem) => getItemId(newItem) === getItemId(prevItem)),
  );
}

delete() {
  if (this.isCursorAtStart()) return this.bell();
  let s1 = this.value.slice(0, this.cursor - 1);
  let s2 = this.value.slice(this.cursor);
  this.value = `${s1}${s2}`;
  this.red = false;
  this.outputError = "";
  this.error = false;
  if (this.isCursorAtStart()) {
    this.cursorOffset = 0;
  } else {
    this.cursorOffset++;
    this.moveCursor(-1);
  }
  this.render();
}

export const limitConcatenatedPathDepth = (path1: ObjectPath, path2: ObjectPath): ObjectPath => {
	const { length: length1 } = path1;
	const { length: length2 } = path2;
	return length1 === 0
		? path2
		: length2 === 0
			? path1
			: length1 + length2 > MAX_PATH_DEPTH
				? [...path1, ...path2.slice(0, MAX_PATH_DEPTH - 1 - path1.length), 'UnknownKey']
				: [...path1, ...path2];
};
